import { useEffect, useState } from "react";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import pattern from "../slike/pattern4.jpg";

export function RezervacijeRecepcionar() {
    const [rezervacije, setRezervacije] = useState([]);
    const [filter, setFilter] = useState("ALL");
    const [showForm, setShowForm] = useState(false);
    const [novaRezervacija, setNovaRezervacija] = useState({
        idGost: "",
        idSoba: "",
        datumPrijave: "",
        datumOdjave: "",
        brojOsoba: "",
        ukupanIznos: "",
        statusRezervacije: "CONFIRMED",
    });

    const getCookie = (name) => {
        const match = document.cookie.match(new RegExp("(^| )" + name + "=([^;]+)"));
        return match ? match[2] : null;
    };
    const userId = getCookie("userId");

    const handleGenerateConfirmation = (rezervacija) => {
        alert(
            `Potvrda rezervacije:\n` +
            `Rezervacija #${rezervacija.idRezervacija}\n` +
            `Gost: ${rezervacija.gost?.ime} ${rezervacija.gost?.prezime}\n` +
            `Soba: ${rezervacija.soba?.brojSobe}\n` +
            `Datum prijave: ${rezervacija.datumPrijave}\n` +
            `Datum odjave: ${rezervacija.datumOdjave}\n` +
            `Broj osoba: ${rezervacija.brojOsoba}\n` +
            `Ukupan iznos: ${rezervacija.ukupanIznos} RSD\n` +
            `Status: ${rezervacija.statusRezervacije}`
        );
    };

    useEffect(() => {
        fetch("http://localhost:8080/reservations/all")
            .then(res => res.json())
            .then(data => {
                if (data && data.data && data.data.values) {
                    setRezervacije(data.data.values);
                }
            })
            .catch(err => console.error("Greška pri učitavanju rezervacija:", err));
    }, []);

    const handleDelete = async (idRezervacija) => {
        if (!window.confirm("Da li ste sigurni da želite da obrišete ovu rezervaciju?")) return;

        try {
            const response = await fetch("http://localhost:8080/reservations/delete", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(idRezervacija),
            });
            const data = await response.json();
            if (response.ok) {
                alert("Rezervacija uspešno obrisana!");
                setRezervacije(prev => prev.filter(r => r.idRezervacija !== idRezervacija));
            } else {
                alert("Greška pri brisanju rezervacije: " + data.message);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setNovaRezervacija(prev => ({ ...prev, [name]: value }));
    };

    const handleAddReservation = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch("http://localhost:8080/reservations/add", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(novaRezervacija),
            });

            const data = await response.json();
            if (response.ok) {
                alert("Rezervacija uspešno dodata!");
                setRezervacije(prev => [...prev, data.data.value]);
                setNovaRezervacija({
                    idGost: "",
                    idSoba: "",
                    datumPrijave: "",
                    datumOdjave: "",
                    brojOsoba: "",
                    ukupanIznos: "",
                    statusRezervacije: "CONFIRMED",
                });
                setShowForm(false);
            } else {
                alert("Greška pri dodavanju rezervacije: " + data.message);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const filtriraneRezervacije =
        filter === "ALL"
            ? rezervacije
            : rezervacije.filter(r => r.statusRezervacije === filter);

    const statusi = ["ALL", "CONFIRMED", "CHECKED_IN", "CHECKED_OUT", "CANCELLED"];

    return (
        <>
            <NavBarRecepcionar />
            <div
                style={{
                    backgroundImage: `url(${pattern})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                    minHeight: "100vh",
                    padding: "40px",
                }}
            >
                <div style={{ textAlign: "center" }}>
                    <h2
                        style={{
                            color: "white",
                            backgroundColor: "rgba(215, 96, 255, 0.6)",
                            padding: "15px 30px",
                            borderRadius: "10px",
                            display: "inline-block",
                        }}
                    >
                        Pregled rezervacija
                    </h2>

                    <div style={{ marginTop: "20px" }}>
                        <button
                            onClick={() => setShowForm(!showForm)}
                            style={{
                                padding: "10px 20px",
                                backgroundColor: "#fff174ff",
                                border: "none",
                                borderRadius: "6px",
                                cursor: "pointer",
                            }}
                        >
                            {showForm ? "Zatvori formu" : "Dodaj rezervaciju"}
                        </button>
                    </div>
                </div>

                {showForm && (
                    <form
                        onSubmit={handleAddReservation}
                        style={{
                            backgroundColor: "white",
                            borderRadius: "10px",
                            padding: "20px",
                            margin: "30px auto",
                            maxWidth: "500px",
                            boxShadow: "0px 2px 8px rgba(0,0,0,0.2)",
                        }}
                    >
                        <h3 style={{ textAlign: "center", color: "#a14ce9" }}>
                            Nova rezervacija
                        </h3>
                        <input
                            type="number"
                            name="idGost"
                            placeholder="ID gosta"
                            value={novaRezervacija.idGost}
                            onChange={handleChange}
                            required
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        />
                        <input
                            type="number"
                            name="idSoba"
                            placeholder="ID sobe"
                            value={novaRezervacija.idSoba}
                            onChange={handleChange}
                            required
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        />
                        <input
                            type="date"
                            name="datumPrijave"
                            value={novaRezervacija.datumPrijave}
                            onChange={handleChange}
                            required
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        />
                        <input
                            type="date"
                            name="datumOdjave"
                            value={novaRezervacija.datumOdjave}
                            onChange={handleChange}
                            required
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        />
                        <input
                            type="number"
                            name="brojOsoba"
                            placeholder="Broj osoba"
                            value={novaRezervacija.brojOsoba}
                            onChange={handleChange}
                            required
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        />
                        <input
                            type="number"
                            name="ukupanIznos"
                            placeholder="Ukupan iznos (RSD)"
                            value={novaRezervacija.ukupanIznos}
                            onChange={handleChange}
                            required
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        />
                        <select
                            name="statusRezervacije"
                            value={novaRezervacija.statusRezervacije}
                            onChange={handleChange}
                            style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
                        >
                            <option value="CONFIRMED">CONFIRMED</option>
                            <option value="CHECKED_IN">CHECKED_IN</option>
                            <option value="CHECKED_OUT">CHECKED_OUT</option>
                            <option value="CANCELLED">CANCELLED</option>
                        </select>
                        <button
                            type="submit"
                            style={{
                                width: "100%",
                                padding: "10px",
                                backgroundColor: "#a14ce9",
                                color: "white",
                                border: "none",
                                borderRadius: "6px",
                                cursor: "pointer",
                            }}
                        >
                            Sačuvaj rezervaciju
                        </button>
                    </form>
                )}

                {/* Filter dugmad */}
                <div
                    style={{
                        display: "flex",
                        justifyContent: "center",
                        marginBottom: "20px",
                    }}
                >
                    {statusi.map((s) => (
                        <button
                            key={s}
                            onClick={() => setFilter(s)}
                            style={{
                                margin: "0 8px",
                                padding: "8px 16px",
                                backgroundColor:
                                    filter === s ? "#ce7affff" : "#ffffffff",
                                color: filter === s ? "white" : "black",
                                border: "none",
                                borderRadius: "6px",
                                cursor: "pointer",
                            }}
                        >
                            {s === "ALL" ? "Sve" : s.replace("_", " ")}
                        </button>
                    ))}
                </div>

                {/* Kartice rezervacija */}
                <div
                    style={{
                        display: "grid",
                        gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
                        gap: "20px",
                        padding: "0 20px",
                    }}
                >
                    {filtriraneRezervacije.length > 0 ? (
                        filtriraneRezervacije.map((rez) => (
                            <div
                                key={rez.idRezervacija}
                                style={{
                                    backgroundColor: "#f7f9fc",
                                    borderRadius: "10px",
                                    padding: "20px",
                                    boxShadow: "0px 2px 8px rgba(0,0,0,0.1)",
                                }}
                            >
                                <h3>Rezervacija #{rez.idRezervacija}</h3>
                                <p>
                                    <strong>Gost:</strong> {rez.gost?.ime}{" "}
                                    {rez.gost?.prezime}
                                </p>
                                <p>
                                    <strong>Soba:</strong> {rez.soba?.brojSobe}
                                </p>
                                <p>
                                    <strong>Datum prijave:</strong>{" "}
                                    {rez.datumPrijave}
                                </p>
                                <p>
                                    <strong>Datum odjave:</strong>{" "}
                                    {rez.datumOdjave}
                                </p>
                                <p>
                                    <strong>Status:</strong>{" "}
                                    {rez.statusRezervacije}
                                </p>
                                <p>
                                    <strong>Ukupan iznos:</strong>{" "}
                                    {rez.ukupanIznos} RSD
                                </p>

                                <div
                                    style={{
                                        display: "flex",
                                        justifyContent: "flex-end",
                                        marginTop: "10px",
                                    }}
                                >
                                    <button
                                        onClick={() =>
                                            handleDelete(rez.idRezervacija)
                                        }
                                        style={{
                                            backgroundColor: "#fff174ff",
                                            color: "black",
                                            border: "none",
                                            borderRadius: "6px",
                                            padding: "6px 12px",
                                            cursor: "pointer",
                                        }}
                                    >
                                        Obriši
                                    </button>
                                    <button
                                        onClick={() =>
                                            handleGenerateConfirmation(rez)
                                        }
                                        style={{
                                            backgroundColor: "#fff174ff",
                                            color: "black",
                                            border: "none",
                                            borderRadius: "6px",
                                            padding: "6px 12px",
                                            cursor: "pointer",
                                            marginLeft: "8px",
                                        }}
                                    >
                                        Generiši potvrdu
                                    </button>
                                </div>
                            </div>
                        ))
                    ) : (
                        <p style={{ textAlign: "center", width: "100%" }}>
                            Nema rezervacija za odabrani status.
                        </p>
                    )}
                </div>
            </div>
        </>
    );
}
